package com.google.gson.internal;

import com.google.gson.stream.JsonReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class JsonReaderInternalAccessTest {

    private JsonReaderInternalAccess jsonReaderInternalAccess;
    private JsonReader jsonReader;

    @BeforeEach
    void setUp() {
        // Since JsonReaderInternalAccess is abstract and INSTANCE is static,
        // we create a mock for the abstract class to test promoteNameToValue.
        jsonReaderInternalAccess = Mockito.mock(JsonReaderInternalAccess.class);
        jsonReader = Mockito.mock(JsonReader.class);
    }

    @Test
    void testPromoteNameToValue_invokesWithoutException() throws IOException {
        // Arrange
        doCallRealMethod().when(jsonReaderInternalAccess).promoteNameToValue(jsonReader);

        // Act & Assert
        assertThrows(IOException.class, () -> jsonReaderInternalAccess.promoteNameToValue(jsonReader));
    }
}
